<?php require __DIR__.'/config.php'; $action = isset($_GET['action']) ? $_GET['action'] : ''; if($action==='logout'){ session_destroy(); header('Location: index.php'); exit; } if($_SERVER['REQUEST_METHOD']!=='POST'){ json_out(array('ok'=>false,'message'=>'Metode tidak diizinkan'),405); } csrf_check(); if(!empty($_POST['company'])){ json_out(array('ok'=>false,'message'=>'Akses ditolak.'),403); } try{ if($action==='login'){ $id = trim(isset($_POST['identity'])?$_POST['identity']:''); $pw = isset($_POST['password'])?$_POST['password']:''; $st=db()->prepare("SELECT * FROM users WHERE (username=? OR phone=?) AND status='aktif' LIMIT 1"); $st->execute(array($id,$id)); $u=$st->fetch(PDO::FETCH_ASSOC); if(!$u || !password_verify($pw,$u['password'])){ json_out(array('ok'=>false,'message'=>'Akun atau password salah.'),401); } if($u['role']!=='admin' && $u['role']!=='pegawai'){ json_out(array('ok'=>false,'message'=>'Akses hanya untuk admin terbatas dan pegawai terbatas.'),403); } unset($u['password']); $_SESSION['user']=$u; log_action('Login',$u['id']); json_out(array('ok'=>true,'role'=>$u['role'],'message'=>'Login berhasil.')); } $me=current_user(); if(!$me){ json_out(array('ok'=>false,'message'=>'Silakan login ulang.'),401); } if($action==='attendance'){ if(feature_locked('lock_face')){ json_out(array('ok'=>false,'message'=>'Absensi wajah sedang dikunci oleh admin.'),423); } $type = $_POST['type']==='out' ? 'out' : 'in'; $lat = floatval(isset($_POST['lat'])?$_POST['lat']:0); $lng = floatval(isset($_POST['lng'])?$_POST['lng']:0); if(!$lat || !$lng){ json_out(array('ok'=>false,'message'=>'Lokasi belum terbaca. Aktifkan GPS.')); } $dist = distance_m($lat,$lng,floatval(setting('office_lat')),floatval(setting('office_lng'))); $inside = $dist <= floatval(setting('radius_m')) ? 1 : 0; $photo=''; if(!empty($_POST['photo']) && strpos($_POST['photo'],'data:image')===0){ $raw = preg_replace('#^data:image/\w+;base64,#','',$_POST['photo']); $bin = base64_decode($raw); if($bin && strlen($bin)<4000000){ $photo='uploads/photos/absen_'.$me['id'].'_'.time().'.jpg'; file_put_contents(app_path($photo),$bin); } } $st=db()->prepare("INSERT INTO attendance(user_id,type,lat,lng,distance_m,inside_area,photo,note,created_at) VALUES(?,?,?,?,?,?,?,?,?)"); $st->execute(array($me['id'],$type,$lat,$lng,$dist,$inside,$photo,$inside?'Dalam Area':'Luar Area',date('Y-m-d H:i:s'))); log_action('Absensi '.($type==='in'?'Masuk':'Pulang'),$me['id']); json_out(array('ok'=>true,'inside'=>$inside,'distance'=>round($dist),'message'=>'Absensi tersimpan.')); } if($action==='leave'){ $st=db()->prepare("INSERT INTO leaves(user_id,kind,date_start,date_end,reason,created_at) VALUES(?,?,?,?,?,?)"); $st->execute(array($me['id'],trim($_POST['kind']),trim($_POST['date_start']),trim($_POST['date_end']),trim($_POST['reason']),date('Y-m-d H:i:s'))); log_action('Ajukan Izin',$me['id']); json_out(array('ok'=>true,'message'=>'Izin berhasil dikirim.')); } if($action==='password'){ $st=db()->prepare("SELECT password FROM users WHERE id=?"); $st->execute(array($me['id'])); $hash=$st->fetchColumn(); if(!password_verify($_POST['old_password'],$hash)){ json_out(array('ok'=>false,'message'=>'Password lama salah.')); } $st=db()->prepare("UPDATE users SET password=? WHERE id=?"); $st->execute(array(password_hash($_POST['new_password'],PASSWORD_DEFAULT),$me['id'])); log_action('Ubah Password',$me['id']); json_out(array('ok'=>true,'message'=>'Password diperbarui.')); } json_out(array('ok'=>false,'message'=>'Aksi tidak ditemukan'),404); }catch(Exception $e){ @file_put_contents(app_path('data/error.log'),date('c').' '.$e->getMessage()."\n",FILE_APPEND); json_out(array('ok'=>false,'message'=>'Terjadi error. Cek data/error.log'),500); } 